"""Build-time cffi builder for compiled out-of-line mode.

Defines all C API cdef declarations and provides a configure() function
that setup.py calls with build-time parameters (library_dirs, rpath, etc.)
before invoking ffibuilder.compile().
"""
from __future__ import annotations

import os
import sys
from pathlib import Path

from cffi import FFI


ffibuilder = FFI()

# Minimal C preamble for set_source — includes standard headers for the
# types used in the cdef (uint8_t, size_t, etc.). Opaque struct typedefs
# are generated by cffi from the cdef; no real WaveDB headers needed.
# raw_op_t and raw_result_t are fully declared here (not in cdef) so cffi
# uses this definition for field access without generating a conflicting one.
_C_SOURCE = """
#include <stdint.h>
#include <stddef.h>

/* Forward-declare ALL opaque types used in function signatures.
   cffi generates the actual typedefs later in the file, but the
   _cffi_d_ check functions at the top reference the type names
   before the definitions appear. Forward-declaring here avoids
   "unknown type name" errors. These must match the cdef exactly. */
typedef struct refcounter_s refcounter_t;
typedef struct database_s database_t;
typedef struct database_config_s database_config_t;
typedef struct encrypted_database_config_s encrypted_database_config_t;
typedef struct promise_s promise_t;
typedef struct async_error_s async_error_t;
typedef struct database_iterator_s database_iterator_t;
typedef struct path_s path_t;
typedef struct identifier_s identifier_t;
typedef struct database_subtree_s database_subtree_t;
typedef struct graph_layer_config_s graph_layer_config_t;
typedef struct graph_layer_s graph_layer_t;
typedef struct graph_query_s graph_query_t;
typedef struct graph_result_s graph_result_t;
typedef struct graphql_layer_config_s graphql_layer_config_t;
typedef struct graphql_layer_s graphql_layer_t;
typedef struct graphql_result_s graphql_result_t;

/* Fully-declared structs (fields accessible from Python).
   cffi uses this definition for field access via the `...` form in cdef. */
typedef struct { const char* key; size_t key_len; const uint8_t* value; size_t value_len; int type; } raw_op_t;
typedef struct { char* key; size_t key_len; uint8_t* value; size_t value_len; } raw_result_t;
"""

# ---- Types ----
# All WaveDB structs are declared opaque via forward declarations.
# Works identically in API mode — cffi emits the typedef into the generated
# C file; no real header required.
ffibuilder.cdef("""
typedef struct refcounter_s refcounter_t;
typedef struct database_s database_t;
typedef struct database_config_s database_config_t;
typedef struct encrypted_database_config_s encrypted_database_config_t;
typedef struct promise_s promise_t;
typedef struct async_error_s async_error_t;
typedef struct database_iterator_s database_iterator_t;
typedef struct path_s path_t;
typedef struct identifier_s identifier_t;
typedef struct database_subtree_s database_subtree_t;
typedef struct graph_layer_config_s graph_layer_config_t;
typedef struct graph_layer_s graph_layer_t;
typedef struct graph_query_s graph_query_t;
typedef struct graph_result_s graph_result_t;
typedef struct graphql_layer_config_s graphql_layer_config_t;
typedef struct graphql_layer_s graphql_layer_t;
typedef struct graphql_result_s graphql_result_t;

typedef struct { ...; } raw_op_t;
typedef struct { ...; } raw_result_t;
""")

