def configure(library_dir: str, include_dirs: list[str] | None = None) -> None:
    """Call set_source with build-time parameters.

    setup.py calls this after the CMake build produces libwavedb.so in
    library_dir. The rpath ensures the compiled extension finds the .so
    at runtime relative to the package directory.
    """
    if sys.platform == "darwin":
        rpath = "@loader_path/_lib"
    elif sys.platform == "win32":
        rpath = None  # Windows: no rpath; .dll is in the same dir
    else:
        rpath = "$ORIGIN/_lib"

    extra_link_args = []
    if rpath:
        extra_link_args.append(f"-Wl,-rpath,{rpath}")

    kwargs = dict(
        libraries=["wavedb"],
        library_dirs=[library_dir],
        extra_link_args=extra_link_args,
    )
    if include_dirs:
        kwargs["include_dirs"] = include_dirs

    ffibuilder.set_source(
        "wavedb._native_ext",
        _C_SOURCE,
        **kwargs,
    )